/\ network' = receiveAck(network, self)
/\ activeSons' = [activeSons EXCEPT ![self] = activeSons[self] - 1]
/\ UNCHANGED <<terminationDetected, active, parent>>
\/ /\ (~active[self] /\ activeSons[self] = 0 /\ parent[self] # none)
